INSERT INTO `que_choice_py_1` (`q_id`, `unit_id`, `title`, `text`, `options`, `answer`, `hints`, `explanation`, `example`) VALUES

(
  91,
  7,
  '买买买！乘法用起来',
  '一杯奶茶8元，阿强想用Python计算买6杯需要多少钱，他应该使用哪个运算符？',
  '["8 + 6", "8 - 6", "8 * 6", "8 / 6"]',
  3,
  '["想想生活中‘几倍’的关系用什么运算？", "乘法运算符是星号(*)，用于计算倍数或面积。", "总价 = 单价 × 数量，所以是8 * 6。"]',
  '计算多个相同物品的总价是典型的乘法应用场景。在Python中，乘法运算符是星号(*)，表达式8 * 6的结果是48。',
  '计算5个苹果（每个3元）的总价：price = 3 * 5。'
),
(
  92,
  7,
  '分糖果与余数',
  '小美有13颗糖，想平均分给4个好朋友，分完后她自己还能剩几颗？她应该使用哪个运算符来计算剩余的糖果数？',
  '["/", "*", "//", "%"]',
  4,
  '["题目问的是‘剩余’的数量，不是每人分到多少。", "这个运算符常常和‘平均分’、‘剩下’有关。", "取模运算符%用于求除法运算后的余数。"]',
  '取模运算符(%)用于计算一个数除以另一个数后的余数。13除以4商3余1，所以13 % 4的结果是1，即小美自己还剩1颗糖。',
  '计算17除以5的余数：remainder = 17 % 5，结果是2。'
),
(
  93,
  7,
  '整碗端走还是切开分？',
  '10个小朋友想平分7个披萨，每个小朋友能拿到‘完整的’多少个披萨？应该用哪个运算符？',
  '["7 / 10", "7 // 10", "7 % 10", "7 * 10"]',
  2,
  '["‘完整的’披萨，意味着不考虑切成小块的情况。", "/ 的结果可能是小数，// 的结果总是整数。", "整数除法(//)会向下取整，得到商的整数部分。"]',
  '整数除法运算符(//)执行除法运算后，会丢弃小数部分，只返回商的整数部分。7 // 10的结果是0，意味着每人分不到一个完整的披萨。',
  '9 // 2 结果是4，因为9除以2等于4.5，向下取整后得到4。'
),
(
  96,
  7,
  '预算大作战',
  '阿强有100元预算，他先花了35元买书，又花了40元买游戏。他用Python计算还剩多少钱：money_left = 100 - 35 + 40。请问这样计算对吗？',
  '["对，因为减法和加法按顺序计算。", "不对，应该加上括号：100 - (35 + 40)。", "对，因为加法和减法优先级相同。", "不对，应该先加后减：100 + 40 - 35。"]',
  2,
  '["思考一下，他总共花了多少钱？", "花的钱应该从总预算中一次性扣除，还是分两次？", "在数学中，连续减法的顺序会影响结果吗？100-35+40 不等于 100-(35+40)。"]',
  '阿强总共花了35+40=75元。正确的计算应是100 - 75 = 25元。而表达式100 - 35 + 40会先算100-35=65，再加40得105，这显然不对。需要加括号改变运算顺序：100 - (35 + 40)。',
  '计算剩余资金时，常将总支出括起来，再从总收入中减去：remaining = total - (expense1 + expense2)。'
),
(
  97,
  7,
  '奇偶判定器',
  '下列哪段代码可以正确判断一个整数变量num是否为偶数？',
  '["if num * 2 == 0:", "if num // 2 == 0:", "if num % 2 == 0:", "if num / 2 == 0:"]',
  3,
  '["偶数的定义是什么？能被2整除。", "在编程中，‘整除’和‘余数为0’是等价的。", "哪个运算符可以得到除法后的余数？"]',
  '判断一个数是否为偶数，即判断它除以2的余数是否为0。取模运算符(%)返回除法运算的余数，因此条件 num % 2 == 0 在num为偶数时为真。',
  '判断7是否为奇数：if 7 % 2 == 1: print("奇数")。'
),
(
  98,
  7,
  '时间和分钟',
  '已知总分钟数total_minutes = 125。想要得到小时数（整数）和剩余的分钟数，应该分别使用什么运算？',
  '["小时：total_minutes / 60， 分钟：total_minutes % 60", "小时：total_minutes // 60， 分钟：total_minutes % 60", "小时：total_minutes % 60， 分钟：total_minutes // 60", "小时：total_minutes * 60， 分钟：total_minutes - 60"]',
  2,
  '["125分钟是2小时零5分钟。如何得到2？", "整数除法(//)可以得到‘有多少个完整的60分钟’。", "取模(%)可以得到‘不足一小时的剩余分钟数’。"]',
  '小时数应为总分钟数除以60的整数商，使用整数除法(//)；剩余分钟数为总分钟数除以60的余数，使用取模运算(%)。125 // 60 = 2，125 % 60 = 5。',
  '将200秒转换为分钟和秒：minutes = 200 // 60, seconds = 200 % 60。'
),
(
  101,
  7,
  '字符串的“乘法”',
  '在Python中，表达式 "Ha" * 3 的结果是什么？',
  '["\\\"HaHaHa\\\"", "\\\"Ha3\\\"", "\\\"Ha*3\\\"", "报错，字符串不能和数字相乘"]',
  1,
  '["回忆一下，对字符串使用*运算符有什么特殊效果？", "想想重复输出一行分隔符，比如 print(\\\"-\\\"*10)。", "字符串乘法是重复拼接字符串。"]',
  '在Python中，字符串与整数n相乘，表示将该字符串重复n次并拼接成一个新的字符串。因此"Ha" * 3 的结果是 "HaHaHa"。',
  '"-" * 5 会得到 "-----"。'
),
(
  102,
  7,
  '除法的陷阱',
  '在Python中，执行 1 / 10 * 10，结果最接近以下哪个值？',
  '["1.0", "0.9999999999999999", "10.0", "0.1"]',
  2,
  '["先计算 1 / 10 看看结果。", "浮点数在计算机中表示时可能存在微小的精度误差。", "虽然数学上 (1/10)*10 等于1，但计算机浮点运算可能略有不同。"]',
  '1 / 10 在Python中结果为0.1（一个浮点数），但计算机二进制浮点数无法精确表示十进制0.1，存在微小误差。这个误差在乘以10后会被放大，因此结果可能为0.9999999999999999，而非精确的1.0。',
  '类似地，0.1 + 0.2 的结果是0.30000000000000004，而非0.3。'
),
(
  103,
  7,
  '负数的余数',
  '在Python中，表达式 -7 % 3 的结果是多少？',
  '["-1", "1", "2", "-4"]',
  3,
  '["取模运算的结果符号取决于除数（模数）的符号。", "Python中，a % b 的结果总是与b同号（或为零）。", "想想看，-7除以3，商是-3，余数应该是多少才能使等式成立？"]',
  'Python的取模运算遵循：被除数 = 除数 * 商 + 余数，且 0 <= 余数 < |除数|。对于-7 % 3，商向下取整为-3（因为-7/3 ≈ -2.33，向下取整是-3），余数 = -7 - (3 * -3) = -7 + 9 = 2。',
  '-10 % 4 的结果是2，因为 -10 = 4 * (-3) + 2。'
);

INSERT INTO `que_fill_py_1` (`q_id`, `unit_id`, `title`, `text`, `input`, `output`, `code`, `options`, `answer`, `explanation`, `example`) VALUES

(
  94,
  7,
  '调配神奇药水',
  '魔法师需要根据古老配方计算魔法药水的剂量，请帮他填补代码中的运算符，让程序正确运行。',
  NULL,
  '["魔力点数: 8"]',
  '{"segments": [{"type": "code_block", "lines": [{"type": "code_line", "value": "# 配方: 基础魔力 (3)，月光系数 (2.5)，精华余量 (7)"}, {"type": "code_line", "value": "base = 3"}, {"type": "code_line", "value": "moon_coeff = 2.5"}, {"type": "code_line", "value": "essence = 7"}]}, {"type": "code_inline", "parts": [{"type": "code", "value": "power = base "}, {"type": "slot", "index": 0}, {"type": "code", "value": " moon_coeff "}, {"type": "slot", "index": 1}, {"type": "code", "value": " essence "}, {"type": "slot", "index": 2}, {"type": "code", "value": " 5"}]}, {"type": "code_block", "lines": [{"type": "code_line", "value": "print(f\\\"魔力点数: {power}\\\")"}]}]}',
  '["+", "-", "*", "/", "//", "%"]',
  '[2, 0, 5]',
